from flask import Flask, jsonify, request
from pymongo import MongoClient

app = Flask(__name__)
client = MongoClient('localhost', 27017)
db = client['cms']
users_collection = db['users']

@app.route('/profile', methods=['POST'])
def create_profile():
    user_data = request.json
    users_collection.insert_one(user_data)
    return jsonify({'message': 'Profile created'}), 201

@app.route('/profile/<string:user_id>', methods=['GET'])
def get_profile(user_id):
    user_profile = users_collection.find_one({'_id': user_id})
    if user_profile:
        return jsonify(user_profile), 200
    return jsonify({'message': 'Profile not found'}), 404

@app.route('/profiles', methods=['GET'])
def get_all_profiles():
    profiles = list(users_collection.find())
    return jsonify(profiles), 200

@app.route('/aggregate', methods=['GET'])
def aggregate_profiles():
    pipeline = [
        { '$group': { '_id': '$age', 'total_users': { '$sum': 1 } } }
    ]
    aggregation_result = list(users_collection.aggregate(pipeline))
    return jsonify(aggregation_result), 200

if __name__ == '__main__':
    app.run(debug=True)